const items = $input.all();
const blogs = items.map(item => item.json);
if (!blogs || blogs.length === 0) return [];
return blogs.map(blog => ({ json: { ...blog } }));

// Inject date context and fetch last 5 post titles to avoid repetition
const blog = $json;

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const month = now.getMonth() + 1;
const day = now.getDate();

// Seasonal context hints
const seasonMap = {
  12: 'New Year is coming, Christmas season, gift guides are popular',
  1:  'New Year resolutions, fresh start energy, self-improvement focus',
  2:  "Valentine's Day, love and relationships, winter ending",
  3:  'Spring is starting, renewal, March 8 International Women\'s Day',
  4:  'Spring energy, Easter, outdoor activities returning',
  5:  'Late spring, summer prep, outdoor lifestyle',
  6:  'Early summer, vacations, longer days',
  7:  'Peak summer, travel, heat tips',
  8:  'Late summer, back to school prep, end of vacation',
  9:  'Autumn begins, back to routine, cozy vibes',
  10: 'Deep autumn, Halloween, comfort content',
  11: 'Pre-holiday season, Black Friday, gratitude theme'
};
const seasonHint = seasonMap[month] || 'no special season';

// Fetch recent post titles to avoid repetition
let recentTitles = [];
try {
  const postsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `http://172.17.0.1:8000/api/blogs/${blog.id}/posts`,
    ignoreHttpStatusErrors: true
  });
  const posts = Array.isArray(postsResp) ? postsResp : [];
  recentTitles = posts.slice(0, 7).map(p => p.title);
} catch(e) {
  recentTitles = [];
}

return [{ json: {
  ...blog,
  dateStr,
  seasonHint,
  recentTitles
} }];

