const raw = $json.choices[0].message.content.trim();
const blog = $('Prepare Context').first().json;

let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match[0]);
} catch(e) {
  console.log('Topic parse failed:', raw);
  parsed = { topic: `Best tips for ${blog.niche}`, angle: 'beginner guide', format: 'tip' };
}

return [{ json: { ...parsed, blog } }];

