const content = $json.choices[0].message.content.trim();
const tokens  = $json.usage?.total_tokens || 0;
const prev    = $('Parse Topic').first().json;

return [{ json: {
  content,
  tokens,
  topic:   prev.topic,
  format:  prev.format,
  blog:    prev.blog,
  postId:  Date.now().toString()
} }];

const d = $input.first().json;

const baseUrl = $env.N8N_WEBHOOK_URL || 'http://localhost:5678';
const resumePath = $execution.resumeUrl.replace('http://localhost:5678', '');
const approveUrl = baseUrl + resumePath + '?action=approve';
const rejectUrl  = baseUrl + resumePath + '?action=reject';

const preview = d.content.length > 400 ? d.content.slice(0, 400) + '...' : d.content;

const body = {
  chat_id:    $env.TELEGRAM_MY_ID,
  parse_mode: 'HTML',
  text: `🗂 <b>${d.blog.name}</b>  ·  ${d.blog.niche}\n📌 <b>Channel:</b> ${d.blog.telegram_channel || 'none'}\n🗓 ${d.blog.dateStr || ''}\n\n🏷 <b>Topic:</b> ${d.topic}\n📐 <b>Format:</b> ${d.format}\n🔢 <b>Tokens:</b> ${d.tokens}\n\n━━━━━━━━━━━━━━━━━━\n${preview}\n━━━━━━━━━━━━━━━━━━`,
  reply_markup: {
    inline_keyboard: [[
      { text: '✅ Publish', url: approveUrl },
      { text: '❌ Skip',    url: rejectUrl  }
    ]]
  }
};

await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.telegram.org/bot${$env.TELEGRAM_BOT_TOKEN}/sendMessage`,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(body),
  returnFullResponse: false,
  ignoreHttpStatusErrors: true
});

return [{ json: { ...d, approveUrl, rejectUrl } }];

const query  = $json.query || {};
const action = query.action || 'reject';
const approve = action === 'approve';
const post   = $('Extract Post').first().json;
return [{ json: { approve, action, ...post } }];

const d = $json;

// 1. Save to blog API
await this.helpers.httpRequest({
  method: 'POST',
  url: `http://172.17.0.1:8000/api/blogs/${d.blog.id}/posts`,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    title:    d.topic,
    content:  d.content,
    category: d.format
  }),
  ignoreHttpStatusErrors: true
});

// 2. Post to Telegram channel if configured
if (d.blog.telegram_channel) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${$env.TELEGRAM_BOT_TOKEN}/sendMessage`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      chat_id: d.blog.telegram_channel,
      text:    d.content
    }),
    ignoreHttpStatusErrors: true
  });
}

return [{ json: { status: 'published', blog: d.blog.id, topic: d.topic } }];
